START TRANSACTION;
ALTER TABLE "Purposes" ADD "IsSystem" boolean NOT NULL DEFAULT FALSE;

ALTER TABLE "Purposes" ADD "Type" integer NOT NULL DEFAULT 1;

UPDATE "Purposes" SET "IsSystem" = true WHERE "PurposeReportTypeId" <> 0;

CREATE TABLE "DiscountApprovals" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "RentalId" bigint NOT NULL,
    "CompanyId" bigint NOT NULL,
    "RecommendedAmount" numeric(10,2) NOT NULL,
    "RequestedAmount" numeric(10,2) NOT NULL,
    "DiscountAmount" numeric(10,2) NOT NULL,
    "Status" integer NOT NULL,
    "RequestedById" bigint NOT NULL,
    "DecidedById" bigint,
    "DecidedAt" timestamp with time zone,
    "Comment" text,
    "Deleted" boolean NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    "LogDbEntryId" bigint,
    CONSTRAINT "PK_DiscountApprovals" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_DiscountApprovals_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_DiscountApprovals_LogDbEntries_LogDbEntryId" FOREIGN KEY ("LogDbEntryId") REFERENCES "LogDbEntries" ("Id"),
    CONSTRAINT "FK_DiscountApprovals_Rentals_RentalId" FOREIGN KEY ("RentalId") REFERENCES "Rentals" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_DiscountApprovals_Users_DecidedById" FOREIGN KEY ("DecidedById") REFERENCES "Users" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_DiscountApprovals_Users_RequestedById" FOREIGN KEY ("RequestedById") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "InspectionLinks" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "RentalId" bigint NOT NULL,
    "CompanyId" bigint NOT NULL,
    "Token" uuid NOT NULL,
    "Type" integer NOT NULL,
    "ExpiresAt" timestamp with time zone NOT NULL,
    "RevokedAt" timestamp with time zone,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    "CreatedById" bigint NOT NULL,
    "ModifiedById" bigint NOT NULL,
    "LogDbEntryId" bigint,
    CONSTRAINT "PK_InspectionLinks" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_InspectionLinks_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_InspectionLinks_LogDbEntries_LogDbEntryId" FOREIGN KEY ("LogDbEntryId") REFERENCES "LogDbEntries" ("Id"),
    CONSTRAINT "FK_InspectionLinks_Rentals_RentalId" FOREIGN KEY ("RentalId") REFERENCES "Rentals" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_InspectionLinks_Users_CreatedById" FOREIGN KEY ("CreatedById") REFERENCES "Users" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_InspectionLinks_Users_ModifiedById" FOREIGN KEY ("ModifiedById") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "Inspections" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "RentalId" bigint NOT NULL,
    "CarId" bigint NOT NULL,
    "CompanyId" bigint NOT NULL,
    "Type" integer NOT NULL,
    "Description" text,
    "DamageAmount" numeric(10,2) NOT NULL,
    "Status" integer NOT NULL,
    "SavedAt" timestamp with time zone,
    "Deleted" boolean NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    "LogDbEntryId" bigint,
    CONSTRAINT "PK_Inspections" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_Inspections_Cars_CarId" FOREIGN KEY ("CarId") REFERENCES "Cars" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_Inspections_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_Inspections_LogDbEntries_LogDbEntryId" FOREIGN KEY ("LogDbEntryId") REFERENCES "LogDbEntries" ("Id"),
    CONSTRAINT "FK_Inspections_Rentals_RentalId" FOREIGN KEY ("RentalId") REFERENCES "Rentals" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "RentalDocuments" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "RentalId" bigint NOT NULL,
    "CompanyId" bigint NOT NULL,
    "Type" integer NOT NULL,
    "Status" integer NOT NULL,
    "Number" text,
    "UploadedFileId" uuid,
    "GeneratedAt" timestamp with time zone NOT NULL,
    "Deleted" boolean NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    "CreatedById" bigint NOT NULL,
    "ModifiedById" bigint NOT NULL,
    "LogDbEntryId" bigint,
    CONSTRAINT "PK_RentalDocuments" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_RentalDocuments_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_RentalDocuments_LogDbEntries_LogDbEntryId" FOREIGN KEY ("LogDbEntryId") REFERENCES "LogDbEntries" ("Id"),
    CONSTRAINT "FK_RentalDocuments_Rentals_RentalId" FOREIGN KEY ("RentalId") REFERENCES "Rentals" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_RentalDocuments_UploadedFiles_UploadedFileId" FOREIGN KEY ("UploadedFileId") REFERENCES "UploadedFiles" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_RentalDocuments_Users_CreatedById" FOREIGN KEY ("CreatedById") REFERENCES "Users" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_RentalDocuments_Users_ModifiedById" FOREIGN KEY ("ModifiedById") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "RentalNotifications" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "CompanyId" bigint NOT NULL,
    "UserId" bigint NOT NULL,
    "Trigger" integer NOT NULL,
    "RentalId" bigint,
    "Message" text,
    "IsRead" boolean NOT NULL,
    "TriggerDay" date NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_RentalNotifications" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_RentalNotifications_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_RentalNotifications_Rentals_RentalId" FOREIGN KEY ("RentalId") REFERENCES "Rentals" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_RentalNotifications_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "RentalNotificationSettings" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "CompanyId" bigint NOT NULL,
    "Trigger" integer NOT NULL,
    "PushEnabled" boolean NOT NULL,
    "EmailEnabled" boolean NOT NULL,
    "TelegramEnabled" boolean NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    "LogDbEntryId" bigint,
    CONSTRAINT "PK_RentalNotificationSettings" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_RentalNotificationSettings_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_RentalNotificationSettings_LogDbEntries_LogDbEntryId" FOREIGN KEY ("LogDbEntryId") REFERENCES "LogDbEntries" ("Id")
);

CREATE TABLE "Seasons" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "CompanyId" bigint NOT NULL,
    "Name" text NOT NULL,
    "StartDate" date NOT NULL,
    "EndDate" date NOT NULL,
    "IsPeak" boolean NOT NULL,
    "Deleted" boolean NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    "LogDbEntryId" bigint,
    CONSTRAINT "PK_Seasons" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_Seasons_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_Seasons_LogDbEntries_LogDbEntryId" FOREIGN KEY ("LogDbEntryId") REFERENCES "LogDbEntries" ("Id")
);

CREATE TABLE "InspectionFiles" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "InspectionId" bigint NOT NULL,
    "UploadedFileId" uuid NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    "LogDbEntryId" bigint,
    CONSTRAINT "PK_InspectionFiles" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_InspectionFiles_Inspections_InspectionId" FOREIGN KEY ("InspectionId") REFERENCES "Inspections" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_InspectionFiles_LogDbEntries_LogDbEntryId" FOREIGN KEY ("LogDbEntryId") REFERENCES "LogDbEntries" ("Id"),
    CONSTRAINT "FK_InspectionFiles_UploadedFiles_UploadedFileId" FOREIGN KEY ("UploadedFileId") REFERENCES "UploadedFiles" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "CarSeasonPrices" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "CarId" bigint NOT NULL,
    "TierCode" integer NOT NULL,
    "SeasonId" bigint NOT NULL,
    "DailyRate" numeric(10,2) NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    "LogDbEntryId" bigint,
    CONSTRAINT "PK_CarSeasonPrices" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_CarSeasonPrices_NonNegative" CHECK ("DailyRate" >= 0),
    CONSTRAINT "FK_CarSeasonPrices_Cars_CarId" FOREIGN KEY ("CarId") REFERENCES "Cars" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_CarSeasonPrices_LogDbEntries_LogDbEntryId" FOREIGN KEY ("LogDbEntryId") REFERENCES "LogDbEntries" ("Id"),
    CONSTRAINT "FK_CarSeasonPrices_Seasons_SeasonId" FOREIGN KEY ("SeasonId") REFERENCES "Seasons" ("Id") ON DELETE RESTRICT
);

