CREATE TABLE "CarDrivers" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "CompanyId" bigint NOT NULL,
    "CarId" bigint NOT NULL,
    "DriverId" bigint NOT NULL,
    "Active" boolean NOT NULL,
    "AutoAdded" boolean NOT NULL,
    "LogDbEntryId" bigint,
    CONSTRAINT "PK_CarDrivers" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_CarDrivers_Cars_CarId" FOREIGN KEY ("CarId") REFERENCES "Cars" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_CarDrivers_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_CarDrivers_LogDbEntries_LogDbEntryId" FOREIGN KEY ("LogDbEntryId") REFERENCES "LogDbEntries" ("Id"),
    CONSTRAINT "FK_CarDrivers_Users_DriverId" FOREIGN KEY ("DriverId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

