INSERT INTO "CarDrivers" ("CompanyId", "CarId", "DriverId", "Active", "AutoAdded")
SELECT DISTINCT u."CompanyId", u."CarId", u."Id", true, false
FROM "Users" u
WHERE u."CarId" IS NOT NULL AND u."CompanyId" IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM "CarDrivers" cd
    WHERE cd."CarId" = u."CarId" AND cd."DriverId" = u."Id" AND cd."Active");

